var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 이런......","JPN":"やれやれ……","ENG":"My, oh my...","TWN":"這、怎麼會……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 옛 스승의 귀환이 그리 달갑지만은 않은가 보군.","JPN":"君も、師匠の帰還を手放しで喜んでいるわけではないようだね。","ENG":"I guess you're not too excited about your old Master's return either.","TWN":"看來妳其實並不怎麼想讓昔日的恩師回來啊。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여긴 왜 나타나신 거죠?","JPN":"どうして、こちらへ？","ENG":"What are you doing here?","TWN":"您為什麼會出現在這裡？"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기껏 그 웃기는 깡통에 오만 가지 이유를 붙여서 사장 자리에 앉혀놨는데......","JPN":"せっかくあのボロ缶に屁理屈つけて社長にしたというのに……","ENG":"Do you know how hard it was to make up all those excuses and turn that tin can into the president?","TWN":"我費盡心思幫那個可笑的鐵罐頭編了各種理由，才讓它坐上老闆的位子……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 곳에서 얼쩡거리다 스승님 눈에 띄기라도 하면 그 고생이 모두 물거품이 될 겁니다.","JPN":"こんなところをうろついて、師匠の目にでもとまったら、これまでの苦労はすべて水の泡ですよ。","ENG":"That'll all be in vain if the Master catches you lurking around here.","TWN":"在這種地方鬼鬼祟祟的樣子，要是被師父看到的話，我的努力全都白費了。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......깡통이라니 너무하는군.","JPN":"……ボロ缶だなんて、ひどいな。","ENG":"Tin can? That's a little harsh...","TWN":"……竟然說是鐵罐頭，太過分了。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이래 봬도 구 관리국 전술통제를 총괄하던 핵심 시스템인데 말이지.","JPN":"ああ見えても、旧管理局の戦術統制を総括していたコアシステムだというのに。","ENG":"It may not look like much now, but it once oversaw every aspect of the Old Administration's operations.","TWN":"好歹它也是舊管理局戰術指揮的核心系統啊。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하긴 저도 그 깐깐한 하이브컨트롤이 이런 로봇으로 구성되어 있을 줄은 몰랐군요.","JPN":"あの厳しいハイブコントロールがあんなロボットで構成されているとは、私としても想定外でした。","ENG":"Yeah... I never thought Hive Control would be made up of robots like this.","TWN":"也是，我從沒想過精密的巢穴控制系統竟然是由這種機器人構成的。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 자네가 모르는 건 그 외에도 아직 많다네.","JPN":"ハハ、まだまだ君が知らないことはたくさんあるんだ。","ENG":"Haha! There's still so much you don't know.","TWN":"哈哈，你們不知道的事情還多著呢。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로도 기대해 주면 좋겠군.","JPN":"これからも楽しみにしてほしいな。","ENG":"You'll find out soon enough.","TWN":"妳今後也可以好好期待一下。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다 아직 제 질문에 대한 대답이 없으시군요.","JPN":"それよりも、私の質問にまだお答えいただけないのですね。","ENG":"Anyway, you still haven't answered my question.","TWN":"比起這些，您還沒有回答我的問題呢。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"벌써 여기저기 돌아다닐 만큼 기억과 육체가 안정화 된 건 아닐 텐데요?","JPN":"あちこち動き回れるほど、記憶や体調が安定してきたわけではないと思いますが、","ENG":"I don't think you're ready to be walking around like that. Your memories and body haven't stabilized yet.","TWN":"明明您的記憶和身體都還不夠穩定，無法四處奔走才對。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이렇게 나타나신 이유가 뭐죠?","JPN":"なぜこうやって現れたのです？","ENG":"Why did you decide to show up in the flesh?","TWN":"那您又為什麼會用這個模樣出現？"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 한 번은 직접 눈으로 봐야 할 것 같아서 말이야.","JPN":"やはり一度はこの目で確かめたくてな。","ENG":"I figured I had to see it all with my own eyes.","TWN":"因為不管怎麼樣，我都想用自己的眼睛來確認。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국이 그렇게 멸망하고, 세상에 이터니움을 퍼트리고, 이렇게 <color=#ffd34c>관</color>을 준비하고......","JPN":"旧管理局があんな形で滅亡した後、世の中にエタニウムを広め、こうやって<color=#ffd34c>棺</color>を設けてからも……","ENG":"With the Old Administration in shambles, Eternium scattered throughout the world, and all that effort to prepare this <color=#ffd34c>coffin</color>...","TWN":"舊管理局滅亡，在世界中散播永恆之金，並準備了<color=#ffd34c>棺材</color>……"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......그러고도 20년 가까이 기다려 온 존재가 드디어 나타나지 않았나?","JPN":"20年近く待ちつづけた存在が、ついに現れたじゃないか。","ENG":"We had to wait another 20 years... but the being we had been waiting for finally appeared!","TWN":"……即便如此，我等待了將近20年的這個存在，最終還是沒有出現嗎？"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무리 위험하다고 해도 모니터로만 보는 건 좀 너무한 처사지.","JPN":"危険だとしても、モニターでしか見られないのはあんまりだ。","ENG":"I know it's dangerous, but watching all this through a monitor doesn't do it justice.","TWN":"不管有多危險，我都不可能只是看著螢幕，卻什麼都不做吧。"},"stage":{"bg":"MAINSTREAM_116011","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};